loss = make_loss_fn(sys, labels) do sys
    scga = SCGA(sys; measure, kT, dq)
    res1 = intensities_static(scga, grid1)
    res2 = intensities_static(scga, grid2)
    return squared_error((res1.data, res2.data), (refdata1, refdata2); rescale=true)
end

import Optim

# Optim options / logging
opts = Optim.Options(
    iterations = 500,
    g_tol      = 1e-6,
    show_trace = true,
    show_every = 5,
)

# Run optimization with reverse-mode AD
guess = [0.0, 0.0, 0.0, 0.0]
# opt = Optim.optimize(loss, guess, Optim.LBFGS(), opts)
opt = Optim.optimize(loss, guess, Optim.LBFGS(), opts; autodiff=DI.AutoZygote())

# Comparison with previous fit
J1 = 3.27
previous_fit = [J1, 0.0815*J1, 0.1050*J1, 0.0085*J1]
@show opt.minimizer
@show previous_fit

previous_fit - opt.minimizer
loss(opt.minimizer)

set_params!(sys, labels, opt.minimizer)
scga = SCGA(sys; measure, kT, dq)
res1 = intensities_static(scga, grid1)
res2 = intensities_static(scga, grid2)

fig = Figure()
heatmap(fig[1, 1], centers, centers, reverse(refdata1; dims=1); colormap=:gnuplot2, axis=(; aspect=1))
heatmap(fig[2, 1], centers, centers, reverse(refdata2; dims=1); colormap=:gnuplot2, axis=(; aspect=1))
plot_intensities!(fig[1, 2], res1)
plot_intensities!(fig[2, 2], res2)


using Chairmarks
import FiniteDiff
@b loss(guess)
@b DI.gradient(loss,  DI.AutoZygote(), guess)
@b DI.gradient(loss,  DI.AutoFiniteDiff(), guess)
